#include<bits/stdc++.h>using namespace std;int main(){	ios::sync_with_stdio(false);	cin.tie(0);	cout.tie(0);  	int t;  	cin>>t;	while(t--){		string a,b;		cin>>a>>b;		if(a.size()*2-1<b.size()){			cout<<"NO"<<'\n';			continue; 		} 		bool bb=false;		int al=a.size(),bl=b.size();		for(int i=0;i<al;i++){			for(int j=i;j<al;j++){	            int r=j-i+1;	            if (r>bl) continue;	            int l=bl-r;	            int end=j-l;	            if (end<0) continue;	            bool m=true;	            int id=0;	            for (int k=i;k<=j&&id<bl;k++,id++) {	                if (a[k]!=b[id]) {	                    m=false;	                    break;	                }	            }	            if (!m) continue;	            for (int k=j-1;k>=end&&id<bl;k--,id++) {	                if(a[k]!=b[id]) {	                    m=false;	                    break;	                }	            }	            if (m&&id==bl) {	                cout<<"YES"<<'\n';	                bb=true;	                break;	            }			}			if(bb){				break;			}		}		if(!bb){			cout<<"NO"<<'\n';		}	}	return 0;}